import{_ as e}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as a,c as n,d as p}from"./app.f51cd3c2.js";const s={},r=p(`<h1 id="\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u7684\u9009\u62E9" tabindex="-1"><a class="header-anchor" href="#\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u7684\u9009\u62E9" aria-hidden="true">#</a> \u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u7684\u9009\u62E9</h1><p>\u5728\u524D\u9762\u7684\u57FA\u7840\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u7ED9\u4F60\u4ECB\u7ECD\u8FC7\u7D22\u5F15\u7684\u57FA\u672C\u6982\u5FF5\uFF0C\u76F8\u4FE1\u4F60\u5DF2\u7ECF\u4E86\u89E3\u4E86\u552F\u4E00\u7D22\u5F15\u548C\u666E\u901A\u7D22\u5F15\u7684\u533A\u522B\u3002\u4ECA\u5929\u6211\u4EEC\u5C31\u7EE7\u7EED\u6765\u8C08\u8C08\uFF0C\u5728\u4E0D\u540C\u7684\u4E1A\u52A1\u573A\u666F\u4E0B\uFF0C\u5E94\u8BE5\u9009\u62E9\u666E\u901A\u7D22\u5F15\uFF0C\u8FD8\u662F\u552F\u4E00\u7D22\u5F15\uFF1F</p><p>\u5047\u8BBE\u4F60\u5728\u7EF4\u62A4\u4E00\u4E2A\u5E02\u6C11\u7CFB\u7EDF\uFF0C\u6BCF\u4E2A\u4EBA\u90FD\u6709\u4E00\u4E2A\u552F\u4E00\u7684\u8EAB\u4EFD\u8BC1\u53F7\uFF0C\u800C\u4E14\u4E1A\u52A1\u4EE3\u7801\u5DF2\u7ECF\u4FDD\u8BC1\u4E86\u4E0D\u4F1A\u5199\u5165\u4E24\u4E2A\u91CD\u590D\u7684\u8EAB\u4EFD\u8BC1\u53F7\u3002\u5982\u679C\u5E02\u6C11\u7CFB\u7EDF\u9700\u8981\u6309\u7167\u8EAB\u4EFD\u8BC1\u53F7\u67E5\u59D3\u540D\uFF0C\u5C31\u4F1A\u6267\u884C\u7C7B\u4F3C\u8FD9\u6837\u7684 SQL \u8BED\u53E5\uFF1A</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">select</span> name <span class="token keyword">from</span> CUser <span class="token keyword">where</span> id_card <span class="token operator">=</span> <span class="token string">&#39;xxxxxxxyyyyyyzzzzz&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>\u6240\u4EE5\uFF0C\u4F60\u4E00\u5B9A\u4F1A\u8003\u8651\u5728 id_card \u5B57\u6BB5\u4E0A\u5EFA\u7D22\u5F15\u3002</p><p>\u7531\u4E8E\u8EAB\u4EFD\u8BC1\u53F7\u5B57\u6BB5\u6BD4\u8F83\u5927\uFF0C\u6211\u4E0D\u5EFA\u8BAE\u4F60\u628A\u8EAB\u4EFD\u8BC1\u53F7\u5F53\u505A\u4E3B\u952E\uFF0C\u90A3\u4E48\u73B0\u5728\u4F60\u6709\u4E24\u4E2A\u9009\u62E9\uFF0C\u8981\u4E48\u7ED9 id_card \u5B57\u6BB5\u521B\u5EFA\u552F\u4E00\u7D22\u5F15\uFF0C\u8981\u4E48\u521B\u5EFA\u4E00\u4E2A\u666E\u901A\u7D22\u5F15\u3002\u5982\u679C\u4E1A\u52A1\u4EE3\u7801\u5DF2\u7ECF\u4FDD\u8BC1\u4E86\u4E0D\u4F1A\u5199\u5165\u91CD\u590D\u7684\u8EAB\u4EFD\u8BC1\u53F7\uFF0C\u90A3\u4E48\u8FD9\u4E24\u4E2A\u9009\u62E9\u903B\u8F91\u4E0A\u90FD\u662F\u6B63\u786E\u7684\u3002</p><p>\u73B0\u5728\u6211\u8981\u95EE\u4F60\u7684\u662F\uFF0C\u4ECE\u6027\u80FD\u7684\u89D2\u5EA6\u8003\u8651\uFF0C\u4F60\u9009\u62E9\u552F\u4E00\u7D22\u5F15\u8FD8\u662F\u666E\u901A\u7D22\u5F15\u5462\uFF1F\u9009\u62E9\u7684\u4F9D\u636E\u662F\u4EC0\u4E48\u5462\uFF1F</p><p>\u7B80\u5355\u8D77\u89C1\uFF0C\u6211\u4EEC\u8FD8\u662F\u7528<a href="../%E5%9F%BA%E7%A1%80%E7%AF%87/4%E7%B4%A2%E5%BC%95%EF%BC%88%E4%B8%8A%EF%BC%89">\u7B2C 4 \u7BC7\u6587\u7AE0\u300A\u6DF1\u5165\u6D45\u51FA\u7D22\u5F15\uFF08\u4E0A\uFF09\u300B</a>\u4E2D\u7684\u4F8B\u5B50\u6765\u8BF4\u660E\uFF0C\u5047\u8BBE\u5B57\u6BB5 k \u4E0A\u7684\u503C\u90FD\u4E0D\u91CD\u590D\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/InnoDB\u7684\u7D22\u5F15\u7EC4\u7EC7\u7ED3\u6784.png" alt="" loading="lazy"></p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u5C31\u4ECE\u8FD9\u4E24\u79CD\u7D22\u5F15\u5BF9\u67E5\u8BE2\u8BED\u53E5\u548C\u66F4\u65B0\u8BED\u53E5\u7684\u6027\u80FD\u5F71\u54CD\u6765\u8FDB\u884C\u5206\u6790\u3002</p><h2 id="\u67E5\u8BE2\u8FC7\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u67E5\u8BE2\u8FC7\u7A0B" aria-hidden="true">#</a> \u67E5\u8BE2\u8FC7\u7A0B</h2><p>\u5047\u8BBE\uFF0C\u6267\u884C\u67E5\u8BE2\u7684\u8BED\u53E5\u662F select id from T where k=5\u3002\u8FD9\u4E2A\u67E5\u8BE2\u8BED\u53E5\u5728\u7D22\u5F15\u6811\u4E0A\u67E5\u627E\u7684\u8FC7\u7A0B\uFF0C\u5148\u662F\u901A\u8FC7 B+ \u6811\u4ECE\u6811\u6839\u5F00\u59CB\uFF0C\u6309\u5C42\u641C\u7D22\u5230\u53F6\u5B50\u8282\u70B9\uFF0C\u4E5F\u5C31\u662F\u56FE\u4E2D\u53F3\u4E0B\u89D2\u7684\u8FD9\u4E2A\u6570\u636E\u9875\uFF0C\u7136\u540E\u53EF\u4EE5\u8BA4\u4E3A\u6570\u636E\u9875\u5185\u90E8\u901A\u8FC7\u4E8C\u5206\u6CD5\u6765\u5B9A\u4F4D\u8BB0\u5F55\u3002</p><ul><li>\u5BF9\u4E8E\u666E\u901A\u7D22\u5F15\u6765\u8BF4\uFF0C\u67E5\u627E\u5230\u6EE1\u8DB3\u6761\u4EF6\u7684\u7B2C\u4E00\u4E2A\u8BB0\u5F55 (5,500) \u540E\uFF0C\u9700\u8981\u67E5\u627E\u4E0B\u4E00\u4E2A\u8BB0\u5F55\uFF0C\u76F4\u5230\u78B0\u5230\u7B2C\u4E00\u4E2A\u4E0D\u6EE1\u8DB3 k=5 \u6761\u4EF6\u7684\u8BB0\u5F55\u3002</li><li>\u5BF9\u4E8E\u552F\u4E00\u7D22\u5F15\u6765\u8BF4\uFF0C\u7531\u4E8E\u7D22\u5F15\u5B9A\u4E49\u4E86\u552F\u4E00\u6027\uFF0C\u67E5\u627E\u5230\u7B2C\u4E00\u4E2A\u6EE1\u8DB3\u6761\u4EF6\u7684\u8BB0\u5F55\u540E\uFF0C\u5C31\u4F1A\u505C\u6B62\u7EE7\u7EED\u68C0\u7D22\u3002</li></ul><p>\u90A3\u4E48\uFF0C\u8FD9\u4E2A\u4E0D\u540C\u5E26\u6765\u7684\u6027\u80FD\u5DEE\u8DDD\u4F1A\u6709\u591A\u5C11\u5462\uFF1F\u7B54\u6848\u662F\uFF0C\u5FAE\u4E4E\u5176\u5FAE\u3002</p><p>\u4F60\u77E5\u9053\u7684\uFF0CInnoDB \u7684\u6570\u636E\u662F\u6309\u6570\u636E\u9875\u4E3A\u5355\u4F4D\u6765\u8BFB\u5199\u7684\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5F53\u9700\u8981\u8BFB\u4E00\u6761\u8BB0\u5F55\u7684\u65F6\u5019\uFF0C\u5E76\u4E0D\u662F\u5C06\u8FD9\u4E2A\u8BB0\u5F55\u672C\u8EAB\u4ECE\u78C1\u76D8\u8BFB\u51FA\u6765\uFF0C\u800C\u662F\u4EE5\u9875\u4E3A\u5355\u4F4D\uFF0C\u5C06\u5176\u6574\u4F53\u8BFB\u5165\u5185\u5B58\u3002\u5728 InnoDB \u4E2D\uFF0C\u6BCF\u4E2A\u6570\u636E\u9875\u7684\u5927\u5C0F\u9ED8\u8BA4\u662F 16KB\u3002</p><p>\u56E0\u4E3A\u5F15\u64CE\u662F\u6309\u9875\u8BFB\u5199\u7684\uFF0C\u6240\u4EE5\u8BF4\uFF0C\u5F53\u627E\u5230 k=5 \u7684\u8BB0\u5F55\u7684\u65F6\u5019\uFF0C\u5B83\u6240\u5728\u7684\u6570\u636E\u9875\u5C31\u90FD\u5728\u5185\u5B58\u91CC\u4E86\u3002\u90A3\u4E48\uFF0C\u5BF9\u4E8E\u666E\u901A\u7D22\u5F15\u6765\u8BF4\uFF0C\u8981\u591A\u505A\u7684\u90A3\u4E00\u6B21\u201C\u67E5\u627E\u548C\u5224\u65AD\u4E0B\u4E00\u6761\u8BB0\u5F55\u201D\u7684\u64CD\u4F5C\uFF0C\u5C31\u53EA\u9700\u8981\u4E00\u6B21\u6307\u9488\u5BFB\u627E\u548C\u4E00\u6B21\u8BA1\u7B97\u3002</p><p>\u5F53\u7136\uFF0C\u5982\u679C k=5 \u8FD9\u4E2A\u8BB0\u5F55\u521A\u597D\u662F\u8FD9\u4E2A\u6570\u636E\u9875\u7684\u6700\u540E\u4E00\u4E2A\u8BB0\u5F55\uFF0C\u90A3\u4E48\u8981\u53D6\u4E0B\u4E00\u4E2A\u8BB0\u5F55\uFF0C\u5FC5\u987B\u8BFB\u53D6\u4E0B\u4E00\u4E2A\u6570\u636E\u9875\uFF0C\u8FD9\u4E2A\u64CD\u4F5C\u4F1A\u7A0D\u5FAE\u590D\u6742\u4E00\u4E9B\u3002</p><p>\u4F46\u662F\uFF0C\u6211\u4EEC\u4E4B\u524D\u8BA1\u7B97\u8FC7\uFF0C\u5BF9\u4E8E\u6574\u578B\u5B57\u6BB5\uFF0C\u4E00\u4E2A\u6570\u636E\u9875\u53EF\u4EE5\u653E\u8FD1\u5343\u4E2A key\uFF0C\u56E0\u6B64\u51FA\u73B0\u8FD9\u79CD\u60C5\u51B5\u7684\u6982\u7387\u4F1A\u5F88\u4F4E\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u8BA1\u7B97\u5E73\u5747\u6027\u80FD\u5DEE\u5F02\u65F6\uFF0C\u4ECD\u53EF\u4EE5\u8BA4\u4E3A\u8FD9\u4E2A\u64CD\u4F5C\u6210\u672C\u5BF9\u4E8E\u73B0\u5728\u7684 CPU \u6765\u8BF4\u53EF\u4EE5\u5FFD\u7565\u4E0D\u8BA1\u3002</p><h2 id="\u66F4\u65B0\u8FC7\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u66F4\u65B0\u8FC7\u7A0B" aria-hidden="true">#</a> \u66F4\u65B0\u8FC7\u7A0B</h2><p>\u4E3A\u4E86\u8BF4\u660E\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u5BF9\u66F4\u65B0\u8BED\u53E5\u6027\u80FD\u7684\u5F71\u54CD\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u9700\u8981\u5148\u8DDF\u4F60\u4ECB\u7ECD\u4E00\u4E0B change buffer\u3002</p><p>\u5F53\u9700\u8981\u66F4\u65B0\u4E00\u4E2A\u6570\u636E\u9875\u65F6\uFF0C\u5982\u679C\u6570\u636E\u9875\u5728\u5185\u5B58\u4E2D\u5C31\u76F4\u63A5\u66F4\u65B0\uFF0C\u800C\u5982\u679C\u8FD9\u4E2A\u6570\u636E\u9875\u8FD8\u6CA1\u6709\u5728\u5185\u5B58\u4E2D\u7684\u8BDD\uFF0C\u5728\u4E0D\u5F71\u54CD\u6570\u636E\u4E00\u81F4\u6027\u7684\u524D\u63D0\u4E0B\uFF0CInooDB \u4F1A\u5C06\u8FD9\u4E9B\u66F4\u65B0\u64CD\u4F5C\u7F13\u5B58\u5728 change buffer \u4E2D\uFF0C\u8FD9\u6837\u5C31\u4E0D\u9700\u8981\u4ECE\u78C1\u76D8\u4E2D\u8BFB\u5165\u8FD9\u4E2A\u6570\u636E\u9875\u4E86\u3002\u5728\u4E0B\u6B21\u67E5\u8BE2\u9700\u8981\u8BBF\u95EE\u8FD9\u4E2A\u6570\u636E\u9875\u7684\u65F6\u5019\uFF0C\u5C06\u6570\u636E\u9875\u8BFB\u5165\u5185\u5B58\uFF0C\u7136\u540E\u6267\u884C change buffer \u4E2D\u4E0E\u8FD9\u4E2A\u9875\u6709\u5173\u7684\u64CD\u4F5C\u3002\u901A\u8FC7\u8FD9\u79CD\u65B9\u5F0F\u5C31\u80FD\u4FDD\u8BC1\u8FD9\u4E2A\u6570\u636E\u903B\u8F91\u7684\u6B63\u786E\u6027\u3002</p><p>\u9700\u8981\u8BF4\u660E\u7684\u662F\uFF0C\u867D\u7136\u540D\u5B57\u53EB\u4F5C change buffer\uFF0C\u5B9E\u9645\u4E0A\u5B83\u662F\u53EF\u4EE5\u6301\u4E45\u5316\u7684\u6570\u636E\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0Cchange buffer \u5728\u5185\u5B58\u4E2D\u6709\u62F7\u8D1D\uFF0C\u4E5F\u4F1A\u88AB\u5199\u5165\u5230\u78C1\u76D8\u4E0A\u3002</p><p>\u5C06 change buffer \u4E2D\u7684\u64CD\u4F5C\u5E94\u7528\u5230\u539F\u6570\u636E\u9875\uFF0C\u5F97\u5230\u6700\u65B0\u7ED3\u679C\u7684\u8FC7\u7A0B\u79F0\u4E3A merge\u3002\u9664\u4E86\u8BBF\u95EE\u8FD9\u4E2A\u6570\u636E\u9875\u4F1A\u89E6\u53D1 merge \u5916\uFF0C\u7CFB\u7EDF\u6709\u540E\u53F0\u7EBF\u7A0B\u4F1A\u5B9A\u671F merge\u3002\u5728\u6570\u636E\u5E93\u6B63\u5E38\u5173\u95ED\uFF08shutdown\uFF09\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u4E5F\u4F1A\u6267\u884C merge \u64CD\u4F5C\u3002</p><p>\u663E\u7136\uFF0C\u5982\u679C\u80FD\u591F\u5C06\u66F4\u65B0\u64CD\u4F5C\u5148\u8BB0\u5F55\u5728 change buffer\uFF0C\u51CF\u5C11\u8BFB\u78C1\u76D8\uFF0C\u8BED\u53E5\u7684\u6267\u884C\u901F\u5EA6\u4F1A\u5F97\u5230\u660E\u663E\u7684\u63D0\u5347\u3002\u800C\u4E14\uFF0C\u6570\u636E\u8BFB\u5165\u5185\u5B58\u662F\u9700\u8981\u5360\u7528 buffer pool \u7684\uFF0C\u6240\u4EE5\u8FD9\u79CD\u65B9\u5F0F\u8FD8\u80FD\u591F\u907F\u514D\u5360\u7528\u5185\u5B58\uFF0C\u63D0\u9AD8\u5185\u5B58\u5229\u7528\u7387\u3002</p><p>\u90A3\u4E48\uFF0C<strong>\u4EC0\u4E48\u6761\u4EF6\u4E0B\u53EF\u4EE5\u4F7F\u7528 change buffer \u5462\uFF1F</strong></p><p>\u5BF9\u4E8E\u552F\u4E00\u7D22\u5F15\u6765\u8BF4\uFF0C\u6240\u6709\u7684\u66F4\u65B0\u64CD\u4F5C\u90FD\u8981\u5148\u5224\u65AD\u8FD9\u4E2A\u64CD\u4F5C\u662F\u5426\u8FDD\u53CD\u552F\u4E00\u6027\u7EA6\u675F\u3002\u6BD4\u5982\uFF0C\u8981\u63D2\u5165 (4,400) \u8FD9\u4E2A\u8BB0\u5F55\uFF0C\u5C31\u8981\u5148\u5224\u65AD\u73B0\u5728\u8868\u4E2D\u662F\u5426\u5DF2\u7ECF\u5B58\u5728 k=4 \u7684\u8BB0\u5F55\uFF0C\u800C\u8FD9\u5FC5\u987B\u8981\u5C06\u6570\u636E\u9875\u8BFB\u5165\u5185\u5B58\u624D\u80FD\u5224\u65AD\u3002\u5982\u679C\u90FD\u5DF2\u7ECF\u8BFB\u5165\u5230\u5185\u5B58\u4E86\uFF0C\u90A3\u76F4\u63A5\u66F4\u65B0\u5185\u5B58\u4F1A\u66F4\u5FEB\uFF0C\u5C31\u6CA1\u5FC5\u8981\u4F7F\u7528 change buffer \u4E86\u3002</p><p>\u56E0\u6B64\uFF0C\u552F\u4E00\u7D22\u5F15\u7684\u66F4\u65B0\u5C31\u4E0D\u80FD\u4F7F\u7528 change buffer\uFF0C\u5B9E\u9645\u4E0A\u4E5F\u53EA\u6709\u666E\u901A\u7D22\u5F15\u53EF\u4EE5\u4F7F\u7528\u3002</p><p>change buffer \u7528\u7684\u662F buffer pool \u91CC\u7684\u5185\u5B58\uFF0C\u56E0\u6B64\u4E0D\u80FD\u65E0\u9650\u589E\u5927\u3002change buffer \u7684\u5927\u5C0F\uFF0C\u53EF\u4EE5\u901A\u8FC7\u53C2\u6570 innodb_change_buffer_max_size \u6765\u52A8\u6001\u8BBE\u7F6E\u3002\u8FD9\u4E2A\u53C2\u6570\u8BBE\u7F6E\u4E3A 50 \u7684\u65F6\u5019\uFF0C\u8868\u793A change buffer \u7684\u5927\u5C0F\u6700\u591A\u53EA\u80FD\u5360\u7528 buffer pool \u7684 50%\u3002</p><p>\u73B0\u5728\uFF0C\u4F60\u5DF2\u7ECF\u7406\u89E3\u4E86 change buffer \u7684\u673A\u5236\uFF0C\u90A3\u4E48\u6211\u4EEC\u518D\u4E00\u8D77\u6765\u770B\u770B<strong>\u5982\u679C\u8981\u5728\u8FD9\u5F20\u8868\u4E2D\u63D2\u5165\u4E00\u4E2A\u65B0\u8BB0\u5F55 (4,400) \u7684\u8BDD\uFF0CInnoDB \u7684\u5904\u7406\u6D41\u7A0B\u662F\u600E\u6837\u7684\u3002</strong></p><p>\u7B2C\u4E00\u79CD\u60C5\u51B5\u662F\uFF0C<strong>\u8FD9\u4E2A\u8BB0\u5F55\u8981\u66F4\u65B0\u7684\u76EE\u6807\u9875\u5728\u5185\u5B58\u4E2D</strong>\u3002\u8FD9\u65F6\uFF0CInnoDB \u7684\u5904\u7406\u6D41\u7A0B\u5982\u4E0B\uFF1A</p><ul><li>\u5BF9\u4E8E\u552F\u4E00\u7D22\u5F15\u6765\u8BF4\uFF0C\u627E\u5230 3 \u548C 5 \u4E4B\u95F4\u7684\u4F4D\u7F6E\uFF0C\u5224\u65AD\u5230\u6CA1\u6709\u51B2\u7A81\uFF0C\u63D2\u5165\u8FD9\u4E2A\u503C\uFF0C\u8BED\u53E5\u6267\u884C\u7ED3\u675F\uFF1B</li><li>\u5BF9\u4E8E\u666E\u901A\u7D22\u5F15\u6765\u8BF4\uFF0C\u627E\u5230 3 \u548C 5 \u4E4B\u95F4\u7684\u4F4D\u7F6E\uFF0C\u63D2\u5165\u8FD9\u4E2A\u503C\uFF0C\u8BED\u53E5\u6267\u884C\u7ED3\u675F\u3002</li></ul><p>\u8FD9\u6837\u770B\u6765\uFF0C\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u5BF9\u66F4\u65B0\u8BED\u53E5\u6027\u80FD\u5F71\u54CD\u7684\u5DEE\u522B\uFF0C\u53EA\u662F\u4E00\u4E2A\u5224\u65AD\uFF0C\u53EA\u4F1A\u8017\u8D39\u5FAE\u5C0F\u7684 CPU \u65F6\u95F4\u3002</p><p>\u4F46\uFF0C\u8FD9\u4E0D\u662F\u6211\u4EEC\u5173\u6CE8\u7684\u91CD\u70B9\u3002</p><p>\u7B2C\u4E8C\u79CD\u60C5\u51B5\u662F\uFF0C<strong>\u8FD9\u4E2A\u8BB0\u5F55\u8981\u66F4\u65B0\u7684\u76EE\u6807\u9875\u4E0D\u5728\u5185\u5B58\u4E2D</strong>\u3002\u8FD9\u65F6\uFF0CInnoDB \u7684\u5904\u7406\u6D41\u7A0B\u5982\u4E0B\uFF1A</p><ul><li>\u5BF9\u4E8E\u552F\u4E00\u7D22\u5F15\u6765\u8BF4\uFF0C\u9700\u8981\u5C06\u6570\u636E\u9875\u8BFB\u5165\u5185\u5B58\uFF0C\u5224\u65AD\u5230\u6CA1\u6709\u51B2\u7A81\uFF0C\u63D2\u5165\u8FD9\u4E2A\u503C\uFF0C\u8BED\u53E5\u6267\u884C\u7ED3\u675F\uFF1B</li><li>\u5BF9\u4E8E\u666E\u901A\u7D22\u5F15\u6765\u8BF4\uFF0C\u5219\u662F\u5C06\u66F4\u65B0\u8BB0\u5F55\u5728 change buffer\uFF0C\u8BED\u53E5\u6267\u884C\u5C31\u7ED3\u675F\u4E86\u3002</li></ul><p>\u5C06\u6570\u636E\u4ECE\u78C1\u76D8\u8BFB\u5165\u5185\u5B58\u6D89\u53CA\u968F\u673A IO \u7684\u8BBF\u95EE\uFF0C\u662F\u6570\u636E\u5E93\u91CC\u9762\u6210\u672C\u6700\u9AD8\u7684\u64CD\u4F5C\u4E4B\u4E00\u3002change buffer \u56E0\u4E3A\u51CF\u5C11\u4E86\u968F\u673A\u78C1\u76D8\u8BBF\u95EE\uFF0C\u6240\u4EE5\u5BF9\u66F4\u65B0\u6027\u80FD\u7684\u63D0\u5347\u662F\u4F1A\u5F88\u660E\u663E\u7684\u3002</p><p>\u4E4B\u524D\u6211\u5C31\u78B0\u5230\u8FC7\u4E00\u4EF6\u4E8B\u513F\uFF0C\u6709\u4E2A DBA \u7684\u540C\u5B66\u8DDF\u6211\u53CD\u9988\u8BF4\uFF0C\u4ED6\u8D1F\u8D23\u7684\u67D0\u4E2A\u4E1A\u52A1\u7684\u5E93\u5185\u5B58\u547D\u4E2D\u7387\u7A81\u7136\u4ECE 99% \u964D\u4F4E\u5230\u4E86 75%\uFF0C\u6574\u4E2A\u7CFB\u7EDF\u5904\u4E8E\u963B\u585E\u72B6\u6001\uFF0C\u66F4\u65B0\u8BED\u53E5\u5168\u90E8\u5835\u4F4F\u3002\u800C\u63A2\u7A76\u5176\u539F\u56E0\u540E\uFF0C\u6211\u53D1\u73B0\u8FD9\u4E2A\u4E1A\u52A1\u6709\u5927\u91CF\u63D2\u5165\u6570\u636E\u7684\u64CD\u4F5C\uFF0C\u800C\u4ED6\u5728\u524D\u4E00\u5929\u628A\u5176\u4E2D\u7684\u67D0\u4E2A\u666E\u901A\u7D22\u5F15\u6539\u6210\u4E86\u552F\u4E00\u7D22\u5F15\u3002</p><h2 id="change-buffer-\u7684\u4F7F\u7528\u573A\u666F" tabindex="-1"><a class="header-anchor" href="#change-buffer-\u7684\u4F7F\u7528\u573A\u666F" aria-hidden="true">#</a> change buffer \u7684\u4F7F\u7528\u573A\u666F</h2><p>\u901A\u8FC7\u4E0A\u9762\u7684\u5206\u6790\uFF0C\u4F60\u5DF2\u7ECF\u6E05\u695A\u4E86\u4F7F\u7528 change buffer \u5BF9\u66F4\u65B0\u8FC7\u7A0B\u7684\u52A0\u901F\u4F5C\u7528\uFF0C\u4E5F\u6E05\u695A\u4E86 change buffer \u53EA\u9650\u4E8E\u7528\u5728\u666E\u901A\u7D22\u5F15\u7684\u573A\u666F\u4E0B\uFF0C\u800C\u4E0D\u9002\u7528\u4E8E\u552F\u4E00\u7D22\u5F15\u3002\u90A3\u4E48\uFF0C\u73B0\u5728\u6709\u4E00\u4E2A\u95EE\u9898\u5C31\u662F\uFF1A\u666E\u901A\u7D22\u5F15\u7684\u6240\u6709\u573A\u666F\uFF0C\u4F7F\u7528 change buffer \u90FD\u53EF\u4EE5\u8D77\u5230\u52A0\u901F\u4F5C\u7528\u5417\uFF1F</p><p>\u56E0\u4E3A merge \u7684\u65F6\u5019\u662F\u771F\u6B63\u8FDB\u884C\u6570\u636E\u66F4\u65B0\u7684\u65F6\u523B\uFF0C\u800C change buffer \u7684\u4E3B\u8981\u76EE\u7684\u5C31\u662F\u5C06\u8BB0\u5F55\u7684\u53D8\u66F4\u52A8\u4F5C\u7F13\u5B58\u4E0B\u6765\uFF0C\u6240\u4EE5\u5728\u4E00\u4E2A\u6570\u636E\u9875\u505A merge \u4E4B\u524D\uFF0Cchange buffer \u8BB0\u5F55\u7684\u53D8\u66F4\u8D8A\u591A\uFF08\u4E5F\u5C31\u662F\u8FD9\u4E2A\u9875\u9762\u4E0A\u8981\u66F4\u65B0\u7684\u6B21\u6570\u8D8A\u591A\uFF09\uFF0C\u6536\u76CA\u5C31\u8D8A\u5927\u3002</p><p>\u56E0\u6B64\uFF0C\u5BF9\u4E8E\u5199\u591A\u8BFB\u5C11\u7684\u4E1A\u52A1\u6765\u8BF4\uFF0C\u9875\u9762\u5728\u5199\u5B8C\u4EE5\u540E\u9A6C\u4E0A\u88AB\u8BBF\u95EE\u5230\u7684\u6982\u7387\u6BD4\u8F83\u5C0F\uFF0C\u6B64\u65F6 change buffer \u7684\u4F7F\u7528\u6548\u679C\u6700\u597D\u3002\u8FD9\u79CD\u4E1A\u52A1\u6A21\u578B\u5E38\u89C1\u7684\u5C31\u662F\u8D26\u5355\u7C7B\u3001\u65E5\u5FD7\u7C7B\u7684\u7CFB\u7EDF\u3002</p><p>\u53CD\u8FC7\u6765\uFF0C\u5047\u8BBE\u4E00\u4E2A\u4E1A\u52A1\u7684\u66F4\u65B0\u6A21\u5F0F\u662F\u5199\u5165\u4E4B\u540E\u9A6C\u4E0A\u4F1A\u505A\u67E5\u8BE2\uFF0C\u90A3\u4E48\u5373\u4F7F\u6EE1\u8DB3\u4E86\u6761\u4EF6\uFF0C\u5C06\u66F4\u65B0\u5148\u8BB0\u5F55\u5728 change buffer\uFF0C\u4F46\u4E4B\u540E\u7531\u4E8E\u9A6C\u4E0A\u8981\u8BBF\u95EE\u8FD9\u4E2A\u6570\u636E\u9875\uFF0C\u4F1A\u7ACB\u5373\u89E6\u53D1 merge \u8FC7\u7A0B\u3002\u8FD9\u6837\u968F\u673A\u8BBF\u95EE IO \u7684\u6B21\u6570\u4E0D\u4F1A\u51CF\u5C11\uFF0C\u53CD\u800C\u589E\u52A0\u4E86 change buffer \u7684\u7EF4\u62A4\u4EE3\u4EF7\u3002\u6240\u4EE5\uFF0C\u5BF9\u4E8E\u8FD9\u79CD\u4E1A\u52A1\u6A21\u5F0F\u6765\u8BF4\uFF0Cchange buffer \u53CD\u800C\u8D77\u5230\u4E86\u526F\u4F5C\u7528\u3002</p><h2 id="\u7D22\u5F15\u9009\u62E9\u548C\u5B9E\u8DF5" tabindex="-1"><a class="header-anchor" href="#\u7D22\u5F15\u9009\u62E9\u548C\u5B9E\u8DF5" aria-hidden="true">#</a> \u7D22\u5F15\u9009\u62E9\u548C\u5B9E\u8DF5</h2><p>\u56DE\u5230\u6211\u4EEC\u6587\u7AE0\u5F00\u5934\u7684\u95EE\u9898\uFF0C\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u5E94\u8BE5\u600E\u4E48\u9009\u62E9\u3002\u5176\u5B9E\uFF0C\u8FD9\u4E24\u7C7B\u7D22\u5F15\u5728\u67E5\u8BE2\u80FD\u529B\u4E0A\u662F\u6CA1\u5DEE\u522B\u7684\uFF0C\u4E3B\u8981\u8003\u8651\u7684\u662F\u5BF9\u66F4\u65B0\u6027\u80FD\u7684\u5F71\u54CD\u3002\u6240\u4EE5\uFF0C\u6211\u5EFA\u8BAE\u4F60\u5C3D\u91CF\u9009\u62E9\u666E\u901A\u7D22\u5F15\u3002</p><p>\u5982\u679C\u6240\u6709\u7684\u66F4\u65B0\u540E\u9762\uFF0C\u90FD\u9A6C\u4E0A\u4F34\u968F\u7740\u5BF9\u8FD9\u4E2A\u8BB0\u5F55\u7684\u67E5\u8BE2\uFF0C\u90A3\u4E48\u4F60\u5E94\u8BE5\u5173\u95ED change buffer\u3002\u800C\u5728\u5176\u4ED6\u60C5\u51B5\u4E0B\uFF0Cchange buffer \u90FD\u80FD\u63D0\u5347\u66F4\u65B0\u6027\u80FD\u3002</p><p>\u5728\u5B9E\u9645\u4F7F\u7528\u4E2D\uFF0C\u4F60\u4F1A\u53D1\u73B0\uFF0C\u666E\u901A\u7D22\u5F15\u548C change buffer \u7684\u914D\u5408\u4F7F\u7528\uFF0C\u5BF9\u4E8E\u6570\u636E\u91CF\u5927\u7684\u8868\u7684\u66F4\u65B0\u4F18\u5316\u8FD8\u662F\u5F88\u660E\u663E\u7684\u3002</p><p>\u7279\u522B\u5730\uFF0C\u5728\u4F7F\u7528\u673A\u68B0\u786C\u76D8\u65F6\uFF0Cchange buffer \u8FD9\u4E2A\u673A\u5236\u7684\u6536\u6548\u662F\u975E\u5E38\u663E\u8457\u7684\u3002\u6240\u4EE5\uFF0C\u5F53\u4F60\u6709\u4E00\u4E2A\u7C7B\u4F3C\u201C\u5386\u53F2\u6570\u636E\u201D\u7684\u5E93\uFF0C\u5E76\u4E14\u51FA\u4E8E\u6210\u672C\u8003\u8651\u7528\u7684\u662F\u673A\u68B0\u786C\u76D8\u65F6\uFF0C\u90A3\u4F60\u5E94\u8BE5\u7279\u522B\u5173\u6CE8\u8FD9\u4E9B\u8868\u91CC\u7684\u7D22\u5F15\uFF0C\u5C3D\u91CF\u4F7F\u7528\u666E\u901A\u7D22\u5F15\uFF0C\u7136\u540E\u628A change buffer \u5C3D\u91CF\u5F00\u5927\uFF0C\u4EE5\u786E\u4FDD\u8FD9\u4E2A\u201C\u5386\u53F2\u6570\u636E\u201D\u8868\u7684\u6570\u636E\u5199\u5165\u901F\u5EA6\u3002</p><h2 id="change-buffer-\u548C-redo-log" tabindex="-1"><a class="header-anchor" href="#change-buffer-\u548C-redo-log" aria-hidden="true">#</a> change buffer \u548C redo log</h2><p>\u7406\u89E3\u4E86 change buffer \u7684\u539F\u7406\uFF0C\u4F60\u53EF\u80FD\u4F1A\u8054\u60F3\u5230\u6211\u5728\u524D\u9762\u6587\u7AE0\u4E2D\u548C\u4F60\u4ECB\u7ECD\u8FC7\u7684 redo log \u548C WAL\u3002</p><p>\u5728\u524D\u9762\u6587\u7AE0\u7684\u8BC4\u8BBA\u4E2D\uFF0C\u6211\u53D1\u73B0\u6709\u540C\u5B66\u6DF7\u6DC6\u4E86 redo log \u548C change buffer\u3002WAL \u63D0\u5347\u6027\u80FD\u7684\u6838\u5FC3\u673A\u5236\uFF0C\u4E5F\u7684\u786E\u662F\u5C3D\u91CF\u51CF\u5C11\u968F\u673A\u8BFB\u5199\uFF0C\u8FD9\u4E24\u4E2A\u6982\u5FF5\u786E\u5B9E\u5BB9\u6613\u6DF7\u6DC6\u3002\u6240\u4EE5\uFF0C\u8FD9\u91CC\u6211\u628A\u5B83\u4EEC\u653E\u5230\u4E86\u540C\u4E00\u4E2A\u6D41\u7A0B\u91CC\u6765\u8BF4\u660E\uFF0C\u4FBF\u4E8E\u4F60\u533A\u5206\u8FD9\u4E24\u4E2A\u6982\u5FF5\u3002</p><blockquote><p>\u5907\u6CE8\uFF1A\u8FD9\u91CC\uFF0C\u4F60\u53EF\u4EE5\u518D\u56DE\u987E\u4E0B\u7B2C 2 \u7BC7\u6587\u7AE0<a href="../%E5%9F%BA%E7%A1%80%E7%AF%87/2%E6%97%A5%E5%BF%97%E7%B3%BB%E7%BB%9F-SQL%E6%9B%B4%E6%96%B0%E8%AF%AD%E5%8F%A5%E7%9A%84%E6%89%A7%E8%A1%8C">\u300A\u65E5\u5FD7\u7CFB\u7EDF\uFF1A\u4E00\u6761 SQL \u66F4\u65B0\u8BED\u53E5\u662F\u5982\u4F55\u6267\u884C\u7684\uFF1F\u300B</a>\u4E2D\u7684\u76F8\u5173\u5185\u5BB9\u3002</p></blockquote><p>\u73B0\u5728\uFF0C\u6211\u4EEC\u8981\u5728\u8868\u4E0A\u6267\u884C\u8FD9\u4E2A\u63D2\u5165\u8BED\u53E5\uFF1A</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code>mysql<span class="token operator">&gt;</span> <span class="token keyword">insert</span> <span class="token keyword">into</span> t<span class="token punctuation">(</span>id<span class="token punctuation">,</span>k<span class="token punctuation">)</span> <span class="token keyword">values</span><span class="token punctuation">(</span>id1<span class="token punctuation">,</span>k1<span class="token punctuation">)</span><span class="token punctuation">,</span><span class="token punctuation">(</span>id2<span class="token punctuation">,</span>k2<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>\u8FD9\u91CC\uFF0C\u6211\u4EEC\u5047\u8BBE\u5F53\u524D k \u7D22\u5F15\u6811\u7684\u72B6\u6001\uFF0C\u67E5\u627E\u5230\u4F4D\u7F6E\u540E\uFF0Ck1 \u6240\u5728\u7684\u6570\u636E\u9875\u5728\u5185\u5B58 (InnoDB buffer pool) \u4E2D\uFF0Ck2 \u6240\u5728\u7684\u6570\u636E\u9875\u4E0D\u5728\u5185\u5B58\u4E2D\u3002\u5982\u56FE 2 \u6240\u793A\u662F\u5E26 change buffer \u7684\u66F4\u65B0\u72B6\u6001\u56FE\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/\u5E26 change buffer \u7684\u66F4\u65B0\u8FC7\u7A0B.png" alt="\u5E26 change buffer \u7684\u66F4\u65B0\u8FC7\u7A0B" loading="lazy"></p><p>\u5206\u6790\u8FD9\u6761\u66F4\u65B0\u8BED\u53E5\uFF0C\u4F60\u4F1A\u53D1\u73B0\u5B83\u6D89\u53CA\u4E86\u56DB\u4E2A\u90E8\u5206\uFF1A\u5185\u5B58\u3001redo log\uFF08ib_log_fileX\uFF09\u3001 \u6570\u636E\u8868\u7A7A\u95F4\uFF08t.ibd\uFF09\u3001\u7CFB\u7EDF\u8868\u7A7A\u95F4\uFF08ibdata1\uFF09\u3002</p><p>\u8FD9\u6761\u66F4\u65B0\u8BED\u53E5\u505A\u4E86\u5982\u4E0B\u7684\u64CD\u4F5C\uFF08\u6309\u7167\u56FE\u4E2D\u7684\u6570\u5B57\u987A\u5E8F\uFF09\uFF1A</p><ol><li>Page 1 \u5728\u5185\u5B58\u4E2D\uFF0C\u76F4\u63A5\u66F4\u65B0\u5185\u5B58\uFF1B</li><li>Page 2 \u6CA1\u6709\u5728\u5185\u5B58\u4E2D\uFF0C\u5C31\u5728\u5185\u5B58\u7684 change buffer \u533A\u57DF\uFF0C\u8BB0\u5F55\u4E0B\u201C\u6211\u8981\u5F80 Page 2 \u63D2\u5165\u4E00\u884C\u201D\u8FD9\u4E2A\u4FE1\u606F</li><li>\u5C06\u4E0A\u8FF0\u4E24\u4E2A\u52A8\u4F5C\u8BB0\u5165 redo log \u4E2D\uFF08\u56FE\u4E2D 3 \u548C 4\uFF09\u3002</li></ol><p>\u505A\u5B8C\u4E0A\u9762\u8FD9\u4E9B\uFF0C\u4E8B\u52A1\u5C31\u53EF\u4EE5\u5B8C\u6210\u4E86\u3002\u6240\u4EE5\uFF0C\u4F60\u4F1A\u770B\u5230\uFF0C\u6267\u884C\u8FD9\u6761\u66F4\u65B0\u8BED\u53E5\u7684\u6210\u672C\u5F88\u4F4E\uFF0C\u5C31\u662F\u5199\u4E86\u4E24\u5904\u5185\u5B58\uFF0C\u7136\u540E\u5199\u4E86\u4E00\u5904\u78C1\u76D8\uFF08\u4E24\u6B21\u64CD\u4F5C\u5408\u5728\u4E00\u8D77\u5199\u4E86\u4E00\u6B21\u78C1\u76D8\uFF09\uFF0C\u800C\u4E14\u8FD8\u662F\u987A\u5E8F\u5199\u7684\u3002</p><p>\u540C\u65F6\uFF0C\u56FE\u4E2D\u7684\u4E24\u4E2A\u865A\u7EBF\u7BAD\u5934\uFF0C\u662F\u540E\u53F0\u64CD\u4F5C\uFF0C\u4E0D\u5F71\u54CD\u66F4\u65B0\u7684\u54CD\u5E94\u65F6\u95F4\u3002</p><p>\u90A3\u5728\u8FD9\u4E4B\u540E\u7684\u8BFB\u8BF7\u6C42\uFF0C\u8981\u600E\u4E48\u5904\u7406\u5462\uFF1F</p><p>\u6BD4\u5982\uFF0C\u6211\u4EEC\u73B0\u5728\u8981\u6267\u884C select * from t where k in (k1, k2)\u3002\u8FD9\u91CC\uFF0C\u6211\u753B\u4E86\u8FD9\u4E24\u4E2A\u8BFB\u8BF7\u6C42\u7684\u6D41\u7A0B\u56FE\u3002</p><p>\u5982\u679C\u8BFB\u8BED\u53E5\u53D1\u751F\u5728\u66F4\u65B0\u8BED\u53E5\u540E\u4E0D\u4E45\uFF0C\u5185\u5B58\u4E2D\u7684\u6570\u636E\u90FD\u8FD8\u5728\uFF0C\u90A3\u4E48\u6B64\u65F6\u7684\u8FD9\u4E24\u4E2A\u8BFB\u64CD\u4F5C\u5C31\u4E0E\u7CFB\u7EDF\u8868\u7A7A\u95F4\uFF08ibdata1\uFF09\u548C redo log\uFF08ib_log_fileX\uFF09\u65E0\u5173\u4E86\u3002\u6240\u4EE5\uFF0C\u6211\u5728\u56FE\u4E2D\u5C31\u6CA1\u753B\u51FA\u8FD9\u4E24\u90E8\u5206\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/\u5E26 change buffer \u7684\u8BFB\u8FC7\u7A0B.png" alt="\u5E26 change buffer \u7684\u8BFB\u8FC7\u7A0B" loading="lazy"></p><p>\u4ECE\u56FE\u4E2D\u53EF\u4EE5\u770B\u5230\uFF1A</p><ol><li>\u8BFB Page 1 \u7684\u65F6\u5019\uFF0C\u76F4\u63A5\u4ECE\u5185\u5B58\u8FD4\u56DE\u3002\u6709\u51E0\u4F4D\u540C\u5B66\u5728\u524D\u9762\u6587\u7AE0\u7684\u8BC4\u8BBA\u4E2D\u95EE\u5230\uFF0CWAL \u4E4B\u540E\u5982\u679C\u8BFB\u6570\u636E\uFF0C\u662F\u4E0D\u662F\u4E00\u5B9A\u8981\u8BFB\u76D8\uFF0C\u662F\u4E0D\u662F\u4E00\u5B9A\u8981\u4ECE redo log \u91CC\u9762\u628A\u6570\u636E\u66F4\u65B0\u4EE5\u540E\u624D\u53EF\u4EE5\u8FD4\u56DE\uFF1F\u5176\u5B9E\u662F\u4E0D\u7528\u7684\u3002\u4F60\u53EF\u4EE5\u770B\u4E00\u4E0B\u56FE 3 \u7684\u8FD9\u4E2A\u72B6\u6001\uFF0C\u867D\u7136\u78C1\u76D8\u4E0A\u8FD8\u662F\u4E4B\u524D\u7684\u6570\u636E\uFF0C\u4F46\u662F\u8FD9\u91CC\u76F4\u63A5\u4ECE\u5185\u5B58\u8FD4\u56DE\u7ED3\u679C\uFF0C\u7ED3\u679C\u662F\u6B63\u786E\u7684\u3002</li><li>\u8981\u8BFB Page 2 \u7684\u65F6\u5019\uFF0C\u9700\u8981\u628A Page 2 \u4ECE\u78C1\u76D8\u8BFB\u5165\u5185\u5B58\u4E2D\uFF0C\u7136\u540E\u5E94\u7528 change buffer \u91CC\u9762\u7684\u64CD\u4F5C\u65E5\u5FD7\uFF0C\u751F\u6210\u4E00\u4E2A\u6B63\u786E\u7684\u7248\u672C\u5E76\u8FD4\u56DE\u7ED3\u679C\u3002</li></ol><p>\u53EF\u4EE5\u770B\u5230\uFF0C\u76F4\u5230\u9700\u8981\u8BFB Page 2 \u7684\u65F6\u5019\uFF0C\u8FD9\u4E2A\u6570\u636E\u9875\u624D\u4F1A\u88AB\u8BFB\u5165\u5185\u5B58\u3002</p><p>\u6240\u4EE5\uFF0C\u5982\u679C\u8981\u7B80\u5355\u5730\u5BF9\u6BD4\u8FD9\u4E24\u4E2A\u673A\u5236\u5728\u63D0\u5347\u66F4\u65B0\u6027\u80FD\u4E0A\u7684\u6536\u76CA\u7684\u8BDD\uFF0C<strong>redo log \u4E3B\u8981\u8282\u7701\u7684\u662F\u968F\u673A\u5199\u78C1\u76D8\u7684 IO \u6D88\u8017\uFF08\u8F6C\u6210\u987A\u5E8F\u5199\uFF09\uFF0C\u800C change buffer \u4E3B\u8981\u8282\u7701\u7684\u5219\u662F\u968F\u673A\u8BFB\u78C1\u76D8\u7684 IO \u6D88\u8017\u3002</strong></p><h2 id="\u5C0F\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u5C0F\u7ED3" aria-hidden="true">#</a> \u5C0F\u7ED3</h2><p>\u4ECA\u5929\uFF0C\u6211\u4ECE\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u7684\u9009\u62E9\u5F00\u59CB\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u6570\u636E\u7684\u67E5\u8BE2\u548C\u66F4\u65B0\u8FC7\u7A0B\uFF0C\u7136\u540E\u8BF4\u660E\u4E86 change buffer \u7684\u673A\u5236\u4EE5\u53CA\u5E94\u7528\u573A\u666F\uFF0C\u6700\u540E\u8BB2\u5230\u4E86\u7D22\u5F15\u9009\u62E9\u7684\u5B9E\u8DF5\u3002</p><p>\u7531\u4E8E\u552F\u4E00\u7D22\u5F15\u7528\u4E0D\u4E0A change buffer \u7684\u4F18\u5316\u673A\u5236\uFF0C\u56E0\u6B64\u5982\u679C\u4E1A\u52A1\u53EF\u4EE5\u63A5\u53D7\uFF0C\u4ECE\u6027\u80FD\u89D2\u5EA6\u51FA\u53D1\u6211\u5EFA\u8BAE\u4F60\u4F18\u5148\u8003\u8651\u975E\u552F\u4E00\u7D22\u5F15\u3002</p><p>\u6700\u540E\uFF0C\u53C8\u5230\u4E86\u601D\u8003\u9898\u65F6\u95F4\u3002</p><p>\u901A\u8FC7\u56FE 2 \u4F60\u53EF\u4EE5\u770B\u5230\uFF0Cchange buffer \u4E00\u5F00\u59CB\u662F\u5199\u5185\u5B58\u7684\uFF0C\u90A3\u4E48\u5982\u679C\u8FD9\u4E2A\u65F6\u5019\u673A\u5668\u6389\u7535\u91CD\u542F\uFF0C\u4F1A\u4E0D\u4F1A\u5BFC\u81F4 change buffer \u4E22\u5931\u5462\uFF1Fchange buffer \u4E22\u5931\u53EF\u4E0D\u662F\u5C0F\u4E8B\u513F\uFF0C\u518D\u4ECE\u78C1\u76D8\u8BFB\u5165\u6570\u636E\u53EF\u5C31\u6CA1\u6709\u4E86 merge \u8FC7\u7A0B\uFF0C\u5C31\u7B49\u4E8E\u662F\u6570\u636E\u4E22\u5931\u4E86\u3002\u4F1A\u4E0D\u4F1A\u51FA\u73B0\u8FD9\u79CD\u60C5\u51B5\u5462\uFF1F</p>`,73),c=[r];function o(i,f){return a(),n("div",null,c)}const u=e(s,[["render",o],["__file","9\u666E\u901A\u7D22\u5F15\u548C\u552F\u4E00\u7D22\u5F15\u7684\u9009\u62E9.html.vue"]]);export{u as default};
